//------------------------------------------------------------------------------
// sim_clk_gen.sv
// published as part of https://github.com/pConst/basic_verilog
// Konstantin Pavlov, pavlovconst@gmail.com
//------------------------------------------------------------------------------

// INFO ------------------------------------------------------------------------
// Testbench clock generator written in System Verilog
//

`timescale 1ns / 1ps

module sim_clk_gen #( parameter
  FREQ  = 200_000_000,  // in Hz
  PHASE = 0,            // in degrees
  DUTY  = 50,           // in percentage
  DISTORT = 200         // in picoseconds
)(
  input  ena,
  output logic clk,     // ideal clock
  output logic clkd     // distorted clock
);

  real clk_pd     = 1.0 / FREQ * 1e9;        // convert to ns
  real clk_on     = DUTY / 100.0 * clk_pd;
  real clk_off    = (100.0 - DUTY) / 100.0 * clk_pd;
  real start_dly  = clk_pd / 4 * PHASE / 90;

  logic do_clk;

  initial begin
    $display("FREQ      = %0d Hz", FREQ);
    $display("PHASE     = %0d deg", PHASE);
    $display("DUTY      = %0d %%",  DUTY);
    $display("DISTORT   = %0d ps", DISTORT);

    $display("PERIOD    = %0.3f ns", clk_pd);
    $display("CLK_ON    = %0.3f ns", clk_on);
    $display("CLK_OFF   = %0.3f ns", clk_off);
    $display("START_DLY = %0.3f ns", start_dly);
  end

  initial begin
    clk <= 0;
    do_clk <= 1;
  end

  always @ (posedge ena or negedge ena) begin
    if (ena) begin
      #(start_dly) do_clk = 1;
    end else begin
      #(start_dly) do_clk = 0;
    end
  end

  always @(posedge do_clk) begin
    if( do_clk ) begin
      clk = 1;
      while ( do_clk ) begin
        #(clk_on)  clk = 0;
        #(clk_off) clk = 1;
      end
      clk = 0;
    end
  end

  always @(*) begin
    clkd = #($urandom_range(0, DISTORT)*1ps) clk;
  end

endmodule

#------------------------------------------------------------------------------
# compile.tcl
# Konstantin Pavlov, pavlovconst@gmail.com
#------------------------------------------------------------------------------

# INFO ------------------------------------------------------------------------
# Modelsim compile script
# based on "ModelSimSE general compile script version 1.1" by Doulos

# launch the script by "vsim -do compile.tcl" command on linux
# or by "modelsim.exe -do compile.tcl" on windows


# Simply change the project settings in this section
# for each new project. There should be no need to
# modify the rest of the script.
set library_file_list {

  work {fifo_tb.sv
        fifo.sv
        test.vo
        c_rand.v
        edge_detect.sv
        clk_divider.sv}
}

        ../../c_rand.v
        ../../edge_detect.sv
        ../../delay.sv
        ../../clk_divider.sv}
}

set vsim_params "-L altera_mf_ver -L altera_mf -L lpm_ver -L lpm"
# add these parameters when simulating Quartus netlists
# "+transport_int_delays +transport_path_delays -L altera_ver -L altera_lnsim_ver -L cyclonev_ver -L lpm_ver -L sgate_ver -L cyclonev_hssi_ver -L altera_mf_ver -L cyclonev_pcie_hip_ver"

set top_level work.fifo_tb

# Console commands:
# r = Recompile changed and dependent files
# rr = Recompile everything
# q = Quit without confirmation

# After sourcing the script from ModelSim for the
# first time use these commands to recompile.
proc r  {} {uplevel #0 source compile.tcl}
proc rr {} {global last_compile_time
            set last_compile_time 0
            r                            }
proc q  {} {quit -force                  }

#Does this installation support Tk?
set tk_ok 1
if [catch {package require Tk}] {set tk_ok 0}

# Prefer a fixed point font for the transcript
set PrefMain(font) {Courier 10 roman normal}

# Compile out of date files
set time_now [clock seconds]
if [catch {set last_compile_time}] {
  set last_compile_time 0
}
foreach {library file_list} $library_file_list {
  vlib $library
  vmap work $library
  foreach file $file_list {
    if { $last_compile_time < [file mtime $file] } {
      if [regexp {.vhdl?$} $file] {
        vcom -93 $file
      } else {
        vlog $file
      }
      set last_compile_time 0
    }
  }
}
set last_compile_time $time_now

# Load the simulation
eval vsim $top_level $vsim_params

# Load saved wave patterns
do wave.do

# Run the simulation
run 100us

wave zoom range 0 100us

# How long since project began?
if {[file isfile start_time.txt] == 0} {
  set f [open start_time.txt w]
  puts $f "Start time was [clock seconds]"
  close $f
} else {
  set f [open start_time.txt r]
  set line [gets $f]
  close $f
  regexp {\d+} $line start_time
  set total_time [expr ([clock seconds]-$start_time)/60]
  puts "Project time is $total_time minutes"
}

